targets.expr:
topk(10,
  sum by (db) (
    (
      redis_server_used_memory{cluster="$cluster", role="master"}
      * on(db, cluster) group_left
        db_replication_factor
    )
    or
    (
      redis_server_used_memory{cluster="$cluster"}
      unless on(db, cluster) db_replication_factor
    )
  )
)

100*(1 - 
  node_filesystem_avail_bytes{cluster="$cluster", node="$node", fstype!~"overlay|tmpfs|efivarfs", mountpoint!="/boot/efi" } 
/
  node_filesystem_size_bytes{cluster="$cluster", node="$node", fstype!~"overlay|tmpfs|efivarfs", mountpoint!="/boot/efi"}
)

max by(filename) (
  max_over_time(node_cert_expires_in_seconds{cluster="$cluster", filename=~"api_cert.pem| cm_cert.pem| metrics_exporter_cert.pem| proxy_cert.pem| syncer_cert.pem| trusted_ca.pem"}[5m])
) / 86400
